"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[8458],{2560:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"/2024/01/26/Xiphium-W04-Update/Index","metadata":{"permalink":"/xiphium-documentation/blog/2024/01/26/Xiphium-W04-Update/Index","editUrl":"https://github.com/Iribov/xiphium-documentation/blog/blog/2024-01-26-Xiphium-W04-Update/Index.md","source":"@site/blog/2024-01-26-Xiphium-W04-Update/Index.md","title":"Xiphium 2024-W04 update","description":"Here is the weekly update of (significant) changes made in Xiphium this week, extracted from Github.","date":"2024-01-26T00:00:00.000Z","formattedDate":"January 26, 2024","tags":[],"readingTime":1.835,"hasTruncateMarker":true,"authors":[{"name":"Jim Kerver","title":"4D Developer @Iribov","url":"https://github.com/Jim-Kerver","imageURL":"https://github.com/Jim-Kerver.png","key":"jim"}],"frontMatter":{"title":"Xiphium 2024-W04 update","authors":["jim"]},"unlisted":false,"nextItem":{"title":"Welcome","permalink":"/xiphium-documentation/blog/welcome"}},"content":"Here is the weekly update of (significant) changes made in Xiphium this week, extracted from Github.\\n\\n\x3c!--truncate--\x3e\\n## Greenhouse Sorting Scanning Menu\\nSome small changes have been made to the Greenhouse sorting scanning menu. It is now possible to add a remark to the sorting!\\n\\nThe popup \'GF_Reason_Not_Planted_Machine\' has been modified with some extra options and changes to current options.\\n\\n## Financial Month (liquidity)\\nThe Financial Month (called Fin_Liq_Month a.k.a. \'Financial Liquidity Month\' on the background) has gotten a new tab added to its list form named \'Creditor\'. 15 fields have been added that are supposed to track the Open and Overdue amounts+Percentages op debitors.\\n\\nAlso, some updates have been made to the \'Update Record\' method. The intension of this change is unclear but it seems to improve current queries.\\n\\n## Financial turnover month\\nSome fields have been added to the Financial turnover month table that track the Debitors Open Percentage and Debitor Overdue PErcentage of both the debitor company and the debitor mother company.\\n## Analysis Order\\nThe Analysis Order detail screen has been subject to change according to feedback from the ISO evaluation. Unused button will be removed, and used buttons will be rearranged. If a button has been removed, and you believe it has to come back, please contact the Analytical Lab.\\n## Analysis Suborder\\nThe Analysis suborder code has received some update to automatically create \'Pathogens to test\' and \'Markers to Test\' links from their respective text fields.\\n\\nAlso, the \'Update Record\' method is currently under construction to remove old/unnecessary code. This should have no effect on daily operations but if there are, contact IT immediately!\\n## Delivery Note\\nA small change has been made to the \'Update Record\' method that automatically enters an employee code and employee name of the account manager involved in the delivery note. The account manager is automatically entered by searching in the Company table with the company code customer from the delivery note.\\n## Order\\nA small change has been made to the \'Update Record\' method optimizing the way company production is taken from order group.\\n## Iribov in Brasil!\\nThe TCPA_SyncExportOrders method now has lines added that take Company code 006, and country \'Brasil\' into account."},{"id":"welcome","metadata":{"permalink":"/xiphium-documentation/blog/welcome","editUrl":"https://github.com/Iribov/xiphium-documentation/blog/blog/2021-08-26-welcome/index.md","source":"@site/blog/2021-08-26-welcome/index.md","title":"Welcome","description":"Docusaurus blogging features are powered by the blog plugin.","date":"2021-08-26T00:00:00.000Z","formattedDate":"August 26, 2021","tags":[{"label":"facebook","permalink":"/xiphium-documentation/blog/tags/facebook"},{"label":"hello","permalink":"/xiphium-documentation/blog/tags/hello"},{"label":"docusaurus","permalink":"/xiphium-documentation/blog/tags/docusaurus"}],"readingTime":0.405,"hasTruncateMarker":false,"authors":[{"name":"S\xe9bastien Lorber","title":"Docusaurus maintainer","url":"https://sebastienlorber.com","imageURL":"https://github.com/slorber.png","key":"slorber"},{"name":"Yangshun Tay","title":"Front End Engineer @ Facebook","url":"https://github.com/yangshun","imageURL":"https://github.com/yangshun.png","key":"yangshun"}],"frontMatter":{"slug":"welcome","title":"Welcome","authors":["slorber","yangshun"],"tags":["facebook","hello","docusaurus"]},"unlisted":false,"prevItem":{"title":"Xiphium 2024-W04 update","permalink":"/xiphium-documentation/blog/2024/01/26/Xiphium-W04-Update/Index"},"nextItem":{"title":"MDX Blog Post","permalink":"/xiphium-documentation/blog/mdx-blog-post"}},"content":"[Docusaurus blogging features](https://docusaurus.io/docs/blog) are powered by the [blog plugin](https://docusaurus.io/docs/api/plugins/@docusaurus/plugin-content-blog).\\n\\nSimply add Markdown files (or folders) to the `blog` directory.\\n\\nRegular blog authors can be added to `authors.yml`.\\n\\nThe blog post date can be extracted from filenames, such as:\\n\\n- `2019-05-30-welcome.md`\\n- `2019-05-30-welcome/index.md`\\n\\nA blog post folder can be convenient to co-locate blog post images:\\n\\n![Docusaurus Plushie](./docusaurus-plushie-banner.jpeg)\\n\\nThe blog supports tags as well!\\n\\n**And if you don\'t want a blog**: just delete this directory, and use `blog: false` in your Docusaurus config."},{"id":"mdx-blog-post","metadata":{"permalink":"/xiphium-documentation/blog/mdx-blog-post","editUrl":"https://github.com/Iribov/xiphium-documentation/blog/blog/2021-08-01-mdx-blog-post.mdx","source":"@site/blog/2021-08-01-mdx-blog-post.mdx","title":"MDX Blog Post","description":"Blog posts support Docusaurus Markdown features, such as MDX.","date":"2021-08-01T00:00:00.000Z","formattedDate":"August 1, 2021","tags":[{"label":"docusaurus","permalink":"/xiphium-documentation/blog/tags/docusaurus"}],"readingTime":0.175,"hasTruncateMarker":false,"authors":[{"name":"S\xe9bastien Lorber","title":"Docusaurus maintainer","url":"https://sebastienlorber.com","imageURL":"https://github.com/slorber.png","key":"slorber"}],"frontMatter":{"slug":"mdx-blog-post","title":"MDX Blog Post","authors":["slorber"],"tags":["docusaurus"]},"unlisted":false,"prevItem":{"title":"Welcome","permalink":"/xiphium-documentation/blog/welcome"}},"content":"Blog posts support [Docusaurus Markdown features](https://docusaurus.io/docs/markdown-features), such as [MDX](https://mdxjs.com/).\\n\\n:::tip\\n\\nUse the power of React to create interactive blog posts.\\n\\n```js\\n<button onClick={() => alert(\'button clicked!\')}>Click me!</button>\\n```\\n\\n<button onClick={() => alert(\'button clicked!\')}>Click me!</button>\\n\\n:::"}]}')}}]);